export const GATE_LIB_MJS = "/**\n * skill-gate-lib.mjs — shared scorer + path helpers for the skill gate.\n *\n * Deterministic skill matcher: scores a user prompt against the cached skill\n * index (name<TAB>description) and returns the top-K skills. Used by:\n *   - skill-gate-eval.mjs  (UserPromptSubmit): writes the required-set contract\n *   - skill-gate-stop.mjs  (Stop): enforces the contract\n *\n * Pure Node ESM, no deps, cross-platform.\n */\n\nimport { readFileSync, existsSync, mkdirSync } from \"node:fs\";\nimport { homedir } from \"node:os\";\nimport { join } from \"node:path\";\n\nconst HOME = homedir();\n\nexport const INDEX_PATH = join(HOME, \".claude\", \".router-cache\", \"skills-index.tsv\");\nexport const GATE_DIR = join(HOME, \".claude\", \".skillgate\");\n\n// Directories where a skill's SKILL.md may live (first hit wins).\nconst SKILL_DIRS = [\n  join(HOME, \".claude\", \"skills\"),\n  join(HOME, \".agents\", \"skills\"),\n  join(HOME, \".config\", \"opencode\", \"skills\"),\n];\n\nconst STOPWORDS = new Set([\n  // EN\n  \"the\", \"and\", \"for\", \"with\", \"that\", \"this\", \"you\", \"your\", \"are\", \"can\",\n  \"have\", \"has\", \"was\", \"will\", \"how\", \"what\", \"why\", \"when\", \"where\", \"into\",\n  \"from\", \"then\", \"than\", \"not\", \"but\", \"all\", \"any\", \"get\", \"use\", \"using\",\n  \"please\", \"make\", \"want\", \"need\", \"help\", \"let\", \"let's\", \"lets\", \"add\",\n  // ES\n  \"que\", \"los\", \"las\", \"una\", \"uno\", \"por\", \"con\", \"para\", \"como\", \"esto\",\n  \"esta\", \"este\", \"eso\", \"porque\", \"pero\", \"todo\", \"todos\", \"toda\", \"todas\",\n  \"muy\", \"mas\", \"más\", \"hacer\", \"haz\", \"hazlo\", \"quiero\", \"porfavor\", \"porfa\",\n  \"favor\", \"mira\", \"listo\", \"ahora\", \"tambien\", \"también\", \"aplica\", \"aplicas\",\n  \"sabes\", \"algo\", \"veo\", \"correcto\", \"aca\", \"acá\", \"aqui\", \"aquí\", \"utiliza\",\n]);\n\n// Ambient/meta tokens that describe the tooling itself, not the task domain.\n// They score at reduced weight so a meta-prompt like \"test it in claude code and\n// opencode\" doesn't force irrelevant skills (claude-code-guide, etc.), while a\n// real request (\"review my code\") still matches via its strong domain tokens.\nconst AMBIENT = new Set([\n  \"claude\", \"code\", \"opencode\", \"skill\", \"skills\", \"hook\", \"hooks\", \"gate\",\n  \"harness\", \"tool\", \"tools\", \"plugin\", \"plugins\", \"run\", \"corre\", \"corré\",\n  \"prueba\", \"pruebalo\", \"pruébalo\", \"probar\", \"test\", \"tests\", \"testing\",\n  \"instalador\", \"instaladores\", \"installer\", \"install\", \"funciona\", \"aplicar\",\n  \"aplicalo\", \"aplícalo\", \"harnes\", \"harneses\",\n  // URL / VCS chrome — a pasted link must not force domain skills.\n  \"github\", \"gitlab\", \"bitbucket\", \"com\", \"http\", \"https\", \"www\", \"git\",\n  \"repo\", \"repos\", \"link\", \"url\", \"raw\", \"main\", \"master\", \"branch\",\n]);\n\n// Score at/above which a match is strong enough to HARD-enforce (gate blocks).\n// Roughly: two strong name-token hits, or one name hit + solid description\n// overlap. Below this a match is only a SOFT suggestion (complement, no block).\nexport const STRONG = 6;\n// Minimum score to surface at all (as a soft suggestion).\nexport const SOFT_MIN = 3;\n\nexport function ensureGateDir() {\n  if (!existsSync(GATE_DIR)) mkdirSync(GATE_DIR, { recursive: true });\n  return GATE_DIR;\n}\n\nexport function gatePaths(sessionId) {\n  const sid = (sessionId || \"default\").replace(/[^A-Za-z0-9_-]/g, \"_\");\n  ensureGateDir();\n  return {\n    required: join(GATE_DIR, `${sid}.required.json`),\n    activated: join(GATE_DIR, `${sid}.activated`),\n    blocks: join(GATE_DIR, `${sid}.blocks`),\n  };\n}\n\nfunction tokenize(text) {\n  return (text || \"\")\n    .toLowerCase()\n    .split(/[^a-z0-9áéíóúñ]+/i)\n    .filter((t) => t.length >= 3 && !STOPWORDS.has(t));\n}\n\n/** Load the skill index as [{name, desc}]. Returns [] if missing. */\nexport function loadIndex(indexPath = INDEX_PATH) {\n  if (!existsSync(indexPath)) return [];\n  const rows = [];\n  for (const line of readFileSync(indexPath, \"utf8\").split(\"\\n\")) {\n    if (!line.trim()) continue;\n    const tab = line.indexOf(\"\\t\");\n    const name = (tab === -1 ? line : line.slice(0, tab)).trim();\n    const desc = (tab === -1 ? \"\" : line.slice(tab + 1)).trim().toLowerCase();\n    if (name) rows.push({ name, desc });\n  }\n  return rows;\n}\n\n/**\n * Score `prompt` against the index. Returns ALL matches with score >= SOFT_MIN,\n * sorted desc, capped at `max` for safety. Name-token hit = 3, name substring =\n * 1.5, description hit = 1; ambient/meta tokens score a fraction of that.\n */\nexport function scoreSkills(prompt, { max = 12, indexPath = INDEX_PATH } = {}) {\n  const tokens = [...new Set(tokenize(prompt))];\n  if (tokens.length === 0) return [];\n  const index = loadIndex(indexPath);\n  if (index.length === 0) return [];\n\n  const scored = [];\n  for (const { name, desc } of index) {\n    const nameFlat = name.toLowerCase().replace(/[-_]/g, \"\");\n    const nameTokens = new Set(name.toLowerCase().split(/[-_]/));\n    let score = 0;\n    for (const t of tokens) {\n      const amb = AMBIENT.has(t);\n      if (nameTokens.has(t)) score += amb ? 0.5 : 3;\n      else if (nameFlat.includes(t)) score += amb ? 0 : 1.5;\n      if (desc.includes(t)) score += amb ? 0.25 : 1;\n    }\n    if (score >= SOFT_MIN) scored.push({ name, desc, score });\n  }\n  scored.sort((a, b) => b.score - a.score);\n  return scored.slice(0, max);\n}\n\n/**\n * Split scored matches into the HARD-enforced `required` set and the SOFT\n * `suggested` set (complementary skills — encouraged, never blocked).\n *\n *   required  = strong matches (score >= STRONG). No rigid cap on how many\n *               genuinely-strong skills apply, but bounded at `hardCap` so the\n *               gate can never wedge on a noisy prompt.\n *   suggested = the remaining decent matches — use ALL that complement the task.\n */\nexport function classify(scored, { hardCap = 4 } = {}) {\n  let required = scored.filter((s) => s.score >= STRONG).slice(0, hardCap).map((s) => s.name);\n  // If nothing is \"strong\" but there's a clear dominant leader (score >= LEADER),\n  // enforce just that one — a plainly single-domain prompt still gets its skill.\n  const LEADER = 5;\n  if (required.length === 0 && scored[0] && scored[0].score >= LEADER) {\n    required = [scored[0].name];\n  }\n  const suggested = scored.filter((s) => !required.includes(s.name)).map((s) => s.name);\n  return { required, suggested };\n}\n\n/** Find and read a skill's SKILL.md body (truncated). \"\" if not found. */\nexport function readSkillBody(name, maxChars = 2500) {\n  for (const dir of SKILL_DIRS) {\n    const p = join(dir, name, \"SKILL.md\");\n    if (existsSync(p)) {\n      const body = readFileSync(p, \"utf8\").trim();\n      return body.length > maxChars ? body.slice(0, maxChars) + \"\\n…[truncated]\" : body;\n    }\n  }\n  return \"\";\n}\n"

export const GATE_EVAL_MJS = "#!/usr/bin/env node\n/**\n * skill-gate-eval.mjs — Claude Code UserPromptSubmit hook.\n *\n * Piece 1 (deterministic contract): scores the prompt, picks the top-K skills,\n * and writes them to the per-session required-set that the Stop gate enforces.\n * Piece 3 (aggressive auto-inject): inlines the top-2 SKILL.md bodies directly\n * into context so the knowledge is present even before any Skill() call.\n *\n * stdout is injected into the model context as a <system-reminder>.\n */\n\nimport { writeFileSync } from \"node:fs\";\nimport { scoreSkills, classify, readSkillBody, gatePaths } from \"./skill-gate-lib.mjs\";\n\nfunction readStdin() {\n  return new Promise((resolve) => {\n    let data = \"\";\n    process.stdin.setEncoding(\"utf8\");\n    process.stdin.on(\"data\", (c) => (data += c));\n    process.stdin.on(\"end\", () => resolve(data));\n    // If nothing is piped, don't hang.\n    setTimeout(() => resolve(data), 250);\n  });\n}\n\nconst DIRECTIVE = `INSTRUCTION: MANDATORY SKILL EVALUATION (a Stop gate enforces the required set)\n\nBefore responding, activate every skill that genuinely helps THIS task. There is\nNO limit — if several skills complement each other, activate ALL of them, not a\ntoken few. Activate via Skill() BEFORE writing code or answering. Naming a skill\nwithout calling Skill() is worthless.`;\n\nconst raw = await readStdin();\nlet prompt = \"\";\nlet sessionId = \"default\";\ntry {\n  const j = JSON.parse(raw);\n  prompt = j.prompt || j.user_prompt || \"\";\n  sessionId = j.session_id || \"default\";\n} catch {\n  prompt = raw; // fallback: raw text\n}\n\nconst scored = scoreSkills(prompt);\nconst { required, suggested } = classify(scored);\nconst p = gatePaths(sessionId);\n\n// Write the contract (HARD set only) + reset the per-turn trackers.\nwriteFileSync(p.required, JSON.stringify({ required, ts: Date.now() }));\nwriteFileSync(p.activated, \"\");\nwriteFileSync(p.blocks, \"0\");\n\n// Always emit the directive so non-matching turns still get the discipline nudge.\nlet out = DIRECTIVE;\n\nif (required.length > 0) {\n  out += `\\n\\nREQUIRED_SKILLS (strong match — the Stop gate BLOCKS turn-end until every one is loaded via Skill()):\\n  ${required.join(\", \")}`;\n}\nif (suggested.length > 0) {\n  out += `\\n\\nSUGGESTED_SKILLS (complementary — NOT enforced, but activate every one that genuinely helps; combining several is expected):\\n  ${suggested.join(\", \")}`;\n}\n\nif (required.length > 0 || suggested.length > 0) {\n  // Aggressive auto-inject: inline up to 2 bodies (required first) as a floor.\n  const order = [...required, ...suggested];\n  const injected = [];\n  for (const name of order.slice(0, 2)) {\n    const body = readSkillBody(name);\n    if (body) injected.push(`\\n----- AUTO-INJECTED SKILL: ${name} -----\\n${body}`);\n  }\n  if (injected.length > 0) {\n    out += `\\n\\nThese skill bodies are pre-loaded for you (still call Skill() on them so the harness registers them + runs any tooling):\\n${injected.join(\"\\n\")}`;\n  }\n}\n\nprocess.stdout.write(out + \"\\n\");\n"

export const GATE_TRACK_MJS = "#!/usr/bin/env node\n/**\n * skill-gate-track.mjs — Claude Code PostToolUse hook (matcher: Skill).\n *\n * Records every Skill() activation into the per-session activated file so the\n * Stop gate can diff required vs activated. Never blocks — pure bookkeeping.\n */\n\nimport { appendFileSync } from \"node:fs\";\nimport { gatePaths } from \"./skill-gate-lib.mjs\";\n\nfunction readStdin() {\n  return new Promise((resolve) => {\n    let data = \"\";\n    process.stdin.setEncoding(\"utf8\");\n    process.stdin.on(\"data\", (c) => (data += c));\n    process.stdin.on(\"end\", () => resolve(data));\n    setTimeout(() => resolve(data), 250);\n  });\n}\n\nconst raw = await readStdin();\ntry {\n  const j = JSON.parse(raw);\n  if (j.tool_name === \"Skill\") {\n    const skill = j.tool_input?.skill || j.tool_input?.name || \"\";\n    if (skill) {\n      const p = gatePaths(j.session_id || \"default\");\n      appendFileSync(p.activated, String(skill).trim() + \"\\n\");\n    }\n  }\n} catch {\n  /* ignore malformed input */\n}\nprocess.exit(0);\n"

export const GATE_STOP_MJS = "#!/usr/bin/env node\n/**\n * skill-gate-stop.mjs — Claude Code Stop hook (THE gate).\n *\n * Diffs the deterministic required-set against the skills actually activated\n * this turn. If any are missing it BLOCKS turn-end and tells the model exactly\n * which Skill() calls to make. This is what turns advisory text into a real\n * enforcement loop.\n *\n * Loop safety: enforces at most ONE block per turn. `stop_hook_active` (set by\n * Claude Code when the model resumed *because* of this hook) short-circuits to\n * allow the turn to end, so we never deadlock.\n */\n\nimport { readFileSync, existsSync, writeFileSync } from \"node:fs\";\nimport { gatePaths } from \"./skill-gate-lib.mjs\";\n\nfunction readStdin() {\n  return new Promise((resolve) => {\n    let data = \"\";\n    process.stdin.setEncoding(\"utf8\");\n    process.stdin.on(\"data\", (c) => (data += c));\n    process.stdin.on(\"end\", () => resolve(data));\n    setTimeout(() => resolve(data), 250);\n  });\n}\n\nfunction allow() {\n  process.exit(0);\n}\n\nconst raw = await readStdin();\nlet j = {};\ntry {\n  j = JSON.parse(raw);\n} catch {\n  allow();\n}\n\n// Already looped once because of us → let it stop, no deadlock.\nif (j.stop_hook_active === true) allow();\n\nconst p = gatePaths(j.session_id || \"default\");\nif (!existsSync(p.required)) allow();\n\nlet required = [];\ntry {\n  required = JSON.parse(readFileSync(p.required, \"utf8\")).required || [];\n} catch {\n  allow();\n}\nif (required.length === 0) allow();\n\nconst activated = new Set(\n  (existsSync(p.activated) ? readFileSync(p.activated, \"utf8\") : \"\")\n    .split(\"\\n\")\n    .map((s) => s.trim().toLowerCase())\n    .filter(Boolean),\n);\n\nconst missing = required.filter((r) => !activated.has(r.toLowerCase()));\n\n// Hard cap: at most one block per turn, even if stop_hook_active is unset.\nlet blocks = 0;\ntry {\n  blocks = parseInt(readFileSync(p.blocks, \"utf8\"), 10) || 0;\n} catch {\n  /* default 0 */\n}\n\nif (missing.length === 0 || blocks >= 1) allow();\n\nwriteFileSync(p.blocks, String(blocks + 1));\nprocess.stdout.write(\n  JSON.stringify({\n    decision: \"block\",\n    reason:\n      `SKILL GATE: faltan skills OBLIGATORIAS de este turno sin activar: ${missing.join(\", \")}. ` +\n      `Activá cada una AHORA con Skill(skill=\"<nombre>\") — en un solo mensaje si son varias — y después terminá. ` +\n      `No anuncies que las vas a usar: llamalas de verdad.`,\n  }),\n);\nprocess.exit(0);\n"

export const PLUGIN_TS = "/**\n * skill-enforcer — OpenCode plugin (installed by router-skills)\n *\n * Real skill-gate (parity with the Claude Code skill-gate hooks). Three pieces:\n *   1. Deterministic contract  — score the user message, split into required\n *      (strong; enforced) and suggested (complementary; uncapped, never blocked).\n *   2. Gate (tool.execute.before) — block the first \"work\" tool until the\n *      required skills are loaded. Real enforcement, not advisory text.\n *   3. Aggressive auto-inject  — inline the top-2 SKILL.md bodies into the\n *      system prompt so the guidance is present even before any skill call.\n *\n * Fail-open: every hook except the intentional gate throw is wrapped so a plugin\n * error can never break the chat pipeline. Auto-loaded from ~/.config/opencode/plugins/.\n */\n\nimport type { Plugin } from \"@opencode-ai/plugin\"\nimport { readFileSync, existsSync } from \"node:fs\"\nimport { homedir } from \"node:os\"\nimport { join } from \"node:path\"\n\nconst HOME = homedir()\nconst INDEX_PATH = join(HOME, \".claude\", \".router-cache\", \"skills-index.tsv\")\nconst SKILL_DIRS = [\n  join(HOME, \".config\", \"opencode\", \"skills\"),\n  join(HOME, \".claude\", \"skills\"),\n  join(HOME, \".agents\", \"skills\"),\n]\n\nconst WORK_TOOLS = new Set([\"write\", \"edit\", \"patch\", \"bash\", \"multiedit\"])\nconst STRONG = 6 // >= this → HARD-enforced (gate blocks). Below → soft suggestion.\nconst SOFT_MIN = 3 // minimum score to surface at all\nconst MARKER = \"MANDATORY SKILL EVALUATION\"\n\nconst STOPWORDS = new Set([\n  \"the\",\"and\",\"for\",\"with\",\"that\",\"this\",\"you\",\"your\",\"are\",\"can\",\"have\",\"has\",\n  \"was\",\"will\",\"how\",\"what\",\"why\",\"when\",\"where\",\"into\",\"from\",\"then\",\"than\",\n  \"not\",\"but\",\"all\",\"any\",\"get\",\"use\",\"using\",\"please\",\"make\",\"want\",\"need\",\n  \"help\",\"let\",\"lets\",\"add\",\"que\",\"los\",\"las\",\"una\",\"uno\",\"por\",\"con\",\"para\",\n  \"como\",\"esto\",\"esta\",\"este\",\"eso\",\"porque\",\"pero\",\"todo\",\"todos\",\"muy\",\"mas\",\n  \"hacer\",\"haz\",\"quiero\",\"porfavor\",\"porfa\",\"favor\",\"mira\",\"listo\",\"ahora\",\n  \"tambien\",\"aplica\",\"utiliza\",\"sabes\",\"algo\",\"aca\",\"aqui\",\n])\n\n// Ambient/meta tokens (the tooling itself, not the task domain) score reduced so\n// a meta-prompt or a pasted link never force-blocks on irrelevant skills.\nconst AMBIENT = new Set([\n  \"claude\",\"code\",\"opencode\",\"skill\",\"skills\",\"hook\",\"hooks\",\"gate\",\"harness\",\n  \"tool\",\"tools\",\"plugin\",\"plugins\",\"run\",\"corre\",\"prueba\",\"pruebalo\",\"probar\",\n  \"test\",\"tests\",\"testing\",\"instalador\",\"instaladores\",\"installer\",\"install\",\n  \"funciona\",\"aplicar\",\"harneses\",\n  \"github\",\"gitlab\",\"bitbucket\",\"com\",\"http\",\"https\",\"www\",\"git\",\"repo\",\"repos\",\n  \"link\",\"url\",\"raw\",\"main\",\"master\",\"branch\",\n])\n\n// ---- deterministic scorer (mirror of skill-gate-lib.mjs) --------------------\n\nlet INDEX_CACHE: { name: string; desc: string }[] | null = null\nfunction loadIndex() {\n  if (INDEX_CACHE) return INDEX_CACHE\n  const rows: { name: string; desc: string }[] = []\n  if (existsSync(INDEX_PATH)) {\n    for (const line of readFileSync(INDEX_PATH, \"utf8\").split(\"\\n\")) {\n      if (!line.trim()) continue\n      const tab = line.indexOf(\"\\t\")\n      const name = (tab === -1 ? line : line.slice(0, tab)).trim()\n      const desc = (tab === -1 ? \"\" : line.slice(tab + 1)).trim().toLowerCase()\n      if (name) rows.push({ name, desc })\n    }\n  }\n  INDEX_CACHE = rows\n  return rows\n}\n\nfunction tokenize(text: string): string[] {\n  return (text || \"\")\n    .toLowerCase()\n    .split(/[^a-z0-9áéíóúñ]+/i)\n    .filter((t) => t.length >= 3 && !STOPWORDS.has(t))\n}\n\nfunction scoreSkills(prompt: string, max = 12): { name: string; score: number }[] {\n  const tokens = [...new Set(tokenize(prompt))]\n  if (tokens.length === 0) return []\n  const scored: { name: string; score: number }[] = []\n  for (const { name, desc } of loadIndex()) {\n    const nameFlat = name.toLowerCase().replace(/[-_]/g, \"\")\n    const nameTokens = new Set(name.toLowerCase().split(/[-_]/))\n    let score = 0\n    for (const t of tokens) {\n      const amb = AMBIENT.has(t)\n      if (nameTokens.has(t)) score += amb ? 0.5 : 3\n      else if (nameFlat.includes(t)) score += amb ? 0 : 1.5\n      if (desc.includes(t)) score += amb ? 0.25 : 1\n    }\n    if (score >= SOFT_MIN) scored.push({ name, score })\n  }\n  scored.sort((a, b) => b.score - a.score)\n  return scored.slice(0, max)\n}\n\n/** Split into HARD required (score >= STRONG, capped) and SOFT suggested (rest). */\nfunction classify(scored: { name: string; score: number }[], hardCap = 4) {\n  let required = scored.filter((s) => s.score >= STRONG).slice(0, hardCap).map((s) => s.name)\n  const LEADER = 5\n  if (required.length === 0 && scored[0] && scored[0].score >= LEADER) {\n    required = [scored[0].name]\n  }\n  const suggested = scored.filter((s) => !required.includes(s.name)).map((s) => s.name)\n  return { required, suggested }\n}\n\nfunction readSkillBody(name: string, maxChars = 2500): string {\n  for (const dir of SKILL_DIRS) {\n    const p = join(dir, name, \"SKILL.md\")\n    if (existsSync(p)) {\n      const body = readFileSync(p, \"utf8\").trim()\n      return body.length > maxChars ? body.slice(0, maxChars) + \"\\n…[truncated]\" : body\n    }\n  }\n  return \"\"\n}\n\n// ---- per-session turn state -------------------------------------------------\n\ntype TurnState = { required: string[]; suggested: string[]; loaded: Set<string>; blocked: boolean }\nconst SESSIONS = new Map<string, TurnState>()\nlet LAST: TurnState | null = null // fallback bridge chat.message → system.transform\n\nfunction stateFor(sessionID?: string): TurnState {\n  const key = sessionID || \"__last__\"\n  let s = SESSIONS.get(key)\n  if (!s) {\n    s = { required: [], suggested: [], loaded: new Set(), blocked: false }\n    SESSIONS.set(key, s)\n  }\n  return s\n}\n\nfunction textFromParts(parts: any[]): string {\n  if (!Array.isArray(parts)) return \"\"\n  return parts\n    .filter((p) => p && (p.type === \"text\" || typeof p.text === \"string\"))\n    .map((p) => p.text || \"\")\n    .join(\" \")\n}\n\nconst DIRECTIVE = `## ${MARKER} (a tool gate enforces the required set)\n\nLoad every skill that genuinely helps THIS task BEFORE running work tools\n(write/edit/bash). There is NO limit — if several skills complement each other,\nload ALL of them. The first work tool is BLOCKED until the required set is\nloaded. Naming a skill without loading it is worthless.`\n\nexport const SkillEnforcer: Plugin = async () => {\n  return {\n    // Piece 1: score the incoming user message, arm the turn contract.\n    \"chat.message\": async (_input: any, output: any) => {\n      try {\n        const parts = output?.parts ?? output?.message?.parts ?? []\n        const { required, suggested } = classify(scoreSkills(textFromParts(parts)))\n        const s = stateFor(output?.message?.sessionID)\n        s.required = required\n        s.suggested = suggested\n        s.loaded = new Set()\n        s.blocked = false\n        LAST = s\n      } catch {\n        // fail open — never break message handling\n      }\n    },\n\n    // Pieces 1 + 3: inject directive + required + suggested + top-2 skill bodies.\n    \"experimental.chat.system.transform\": async (_input: any, output: any) => {\n      try {\n        if (!output || typeof output !== \"object\") return\n        const sys: any[] = Array.isArray(output.system) ? output.system : (output.system = [])\n        if (sys.some((x) => typeof x === \"string\" && x.includes(MARKER))) return // idempotent\n        const s = LAST\n        let block = DIRECTIVE\n        if (s && s.required.length > 0) {\n          block += `\\n\\nREQUIRED_SKILLS (strong match — a work tool is blocked until each is loaded):\\n  ${s.required.join(\", \")}`\n        }\n        if (s && s.suggested.length > 0) {\n          block += `\\n\\nSUGGESTED_SKILLS (complementary — NOT enforced, but load every one that genuinely helps; combining several is expected):\\n  ${s.suggested.join(\", \")}`\n        }\n        if (s && (s.required.length > 0 || s.suggested.length > 0)) {\n          const injected: string[] = []\n          for (const name of [...s.required, ...s.suggested].slice(0, 2)) {\n            const body = readSkillBody(name)\n            if (body) injected.push(`\\n----- AUTO-INJECTED SKILL: ${name} -----\\n${body}`)\n          }\n          if (injected.length > 0) {\n            block += `\\n\\nPre-loaded skill bodies (still call the skill tool so tooling runs):\\n${injected.join(\"\\n\")}`\n          }\n        }\n        const last = sys.length - 1\n        if (last >= 0 && typeof sys[last] === \"string\") sys[last] += \"\\n\\n\" + block\n        else sys.push(block)\n      } catch {\n        // fail open\n      }\n    },\n\n    // Piece 2 tracking: record skill loads.\n    \"tool.execute.after\": async (input: any, output: any) => {\n      try {\n        const tool = String(input?.tool || \"\").toLowerCase()\n        const s = stateFor(input?.sessionID)\n        if (tool.includes(\"skill\")) {\n          const arg = input?.args?.skill || input?.args?.name || output?.title || \"\"\n          if (arg) s.loaded.add(String(arg).trim().toLowerCase())\n        }\n        if (s.required.some((r) => r.toLowerCase() === tool)) s.loaded.add(tool)\n      } catch {\n        // fail open\n      }\n    },\n\n    // Piece 2 gate: block the first work tool until required skills are loaded.\n    // The scoring is fail-open (errors → no block); the block itself is intentional.\n    \"tool.execute.before\": async (input: any, _output: any) => {\n      let missing: string[] = []\n      try {\n        const tool = String(input?.tool || \"\").toLowerCase()\n        if (!WORK_TOOLS.has(tool)) return\n        const s = stateFor(input?.sessionID)\n        if (s.required.length === 0 || s.blocked) return\n        missing = s.required.filter((r) => !s.loaded.has(r.toLowerCase()))\n        if (missing.length === 0) return\n        s.blocked = true // one block per turn — never deadlock\n      } catch {\n        return // fail open — a scorer error must never block work\n      }\n      throw new Error(\n        `SKILL GATE: cargá las skills OBLIGATORIAS de este turno antes de trabajar: ${missing.join(\", \")}. ` +\n          `Usá la herramienta de skills con cada una y volvé a intentar. No las anuncies: cargalas de verdad.`,\n      )\n    },\n  }\n}\n\nexport default SkillEnforcer\n"

export const SKILL_RULE_MD = "# MANDATORY SKILL EVALUATION (a gate enforces the required set)\n\nYou have a large catalog of Agent Skills discovered globally. Before answering a\ntechnical request you MUST evaluate them and load every one that genuinely helps.\n\nRules:\n\n1. Load every skill that helps THIS task before running work tools\n   (write/edit/bash). There is NO limit — if several skills complement each\n   other, load ALL of them, not a token few.\n2. Prefer the MOST SPECIFIC skill (e.g. `nextjs-best-practices`,\n   `laravel-security`) over a broad one (e.g. `coding-standards`) when both match.\n3. Do NOT keep reaching for the same handful of skills out of habit. Re-evaluate\n   the full catalog each turn; the best skill may be one you have never used.\n4. State in one line which you are loading and why, load each via the skill tool\n   BEFORE writing code, then proceed.\n5. If nothing genuinely fits, proceed directly — no forced match.\n\nA tool gate blocks your first work tool until the strongly-matched skills are\nloaded. Naming a skill without loading it is worthless.\n"

